    String getCellName(int row, int cell){
        String cellName = "";
        int asciiCode = 65;     //A
        row = row + 1;
        if(cell<26){
            cellName = ""+(char)(asciiCode+cell)+row+"";
        } else {                            
            cellName = "A"+ (char)(asciiCode+(cell-26))+row+"";
        }
        return cellName;
    }
    
    String getWeekFromTo(int year, int mon, int week){
        String weekFromTo = "";
        Calendar c = new GregorianCalendar();
        c.set(Calendar.YEAR, year);
        c.set(Calendar.MONTH, mon);
        c.set(Calendar.WEEK_OF_MONTH, week);
        int dayOfWeek = c.get(Calendar.DAY_OF_WEEK); 
        Calendar calFirstDayInThisWeek = (Calendar)c.clone();
        calFirstDayInThisWeek.add(Calendar.DATE, c.getActualMinimum(Calendar.DAY_OF_WEEK)-dayOfWeek);
        Calendar calLastDayInThisWeek = (Calendar)c.clone();
        calLastDayInThisWeek.add(Calendar.DATE,c.getActualMaximum(Calendar.DAY_OF_WEEK)-dayOfWeek);
        weekFromTo = 
                 (calFirstDayInThisWeek.getTime().getYear()+1900)+"."+
                 (calFirstDayInThisWeek.getTime().getMonth()+1)+"."+
                 calFirstDayInThisWeek.getTime().getDate()+"~"+
                 (calLastDayInThisWeek.getTime().getYear()+1900)+"."+
                 (calLastDayInThisWeek.getTime().getMonth()+1)+"."+
                 calLastDayInThisWeek.getTime().getDate();
        return weekFromTo;
    }



boolean getAllView(String apName, String channel, String repNameTail, String year, String mon, int sentArea) {
    final String AP_NAME = apName;
    BDBWorker worker = new BDBWorker(AP_NAME);
    final int AREA = 1000130;
    final int REC_NO = 1000173;
    final int REP_NAME = 1000174;
    final int REP_YEAR = 1000176;
    final int REP_MON = 1000177;
    final int REP_STAT = 1000242;
    boolean isAllConfirm = false;
    try {
        SDBQuery q = new SDBQueryFull(worker);
        SDBNode node;
        q.go(REC_NO);
        q.filter(REP_YEAR, year);
        q.filter(REP_MON, mon);
        int viewArea = 0;
        while ((node = q.next()) != null) {
            if (q.dip(REP_NAME).contains(repNameTail) && q.dip(REP_NAME).contains(channel)) {
                if (q.dip(REP_STAT).equals("已確認")) {
                    viewArea = viewArea + 1;
                }
            }
        }
        if (viewArea >= sentArea) {
            isAllConfirm = true;
        }
    } catch (Exception e) {
        System.out.println(e.getMessage());
        throw new RuntimeException("getAllView got an exception. " + e.getMessage());
    } finally {
        worker.commit();
    }
    return isAllConfirm;
}

boolean confirmLog(String apName, String repName, String userId) {

    final String AP_NAME = apName;
    BDBWorker worker = new BDBWorker(AP_NAME);
    final int REC_NO = 1000173;
    final int REP_NAME = 1000174;
    final int USER_ID = 1000178;
    final int REP_STAT = 1000242;
    final int CFM_DATE = 1000243;
    boolean isConfirm = false;
    int rootNodeId = -1;
    try {
        SDBQuery q = new SDBQueryFull(worker);
        SDBNode node;
        q.go(REC_NO);
        q.filter(REP_NAME, repName);
        q.filter(USER_ID, userId);
        if ((node = q.next()) != null) {
            rootNodeId = node.getId();
            if (q.dip(REP_STAT) != null && q.dip(REP_STAT).equals("已確認")) {
                isConfirm = true;
            }
        }
    } catch (Exception e) {
        System.out.println(e.getMessage());
        throw new RuntimeException("confirmLog got an exception. " + e.getMessage());
    } finally {
        worker.commit();
    }
    if (rootNodeId > 0 && !isConfirm) {
        BDBSmartWorker smartWorker = new BDBSmartWorker(AP_NAME);
        smartWorker.setFieldValue(REC_NO, rootNodeId, REP_STAT, "已確認");
        Calendar cal = Calendar.getInstance();
        cal.roll(Calendar.HOUR_OF_DAY, 8); //UTC+8小時
        smartWorker.setFieldValue(REC_NO, rootNodeId, CFM_DATE, cal.getTime().toString());
        isConfirm = true;
    }
    return isConfirm;
}


