String sendType = request.getParameter("sendType");

final String AP_NAME = "diageo";
SDBNode node;
final int CHANNEL = 1000058;
final int AREA = 1000130;
final int USER_ID = DConst.USER_USERID_EMAIL;
final int USER_GROUP = DConst.USER_GROUP;
final int USER_STATUS = DConst.USER_STATUS;
final int USER_NAME = DConst.USER_NAME;
final String SE = "Sales";
final String SM = "SM";
final String CM = "CM/CL";
final String PS = "PS/PLS";
