                    encodeEmail = java.net.URLEncoder.encode(new DES().encrypt(email), "utf-8");
                    userName = "Hi " + userName + "您好,<br/>";

                    subject = "全國MOT週報表(" + weekFromTo + ")";
                    message = "<img src='https://" + request.getServerName() + "/cust/diageo/mailHeader.jpg' />" + "<div style='line-height:200%;margin-left:50px'>";
                    message = message + userName + "本週的全國MOT週報表已可讀取!<br/>" + "您可點選下方連結讀取報表。<br/>";
